def solve():
    n = int(input())
    a = list(map(int, input().split()))

    def differences(b_set):
        b = list(b_set)
        diffs = set()
        for x in b:
            for y in b:
                diffs.add(x - y)
        return diffs

    def search(b_set, remaining_a):
        diffs = differences(b_set)
        # Filter remaining_a to only uncovered
        still_needed = [x for x in remaining_a if x not in diffs]
        if not still_needed:
            return True
        if len(b_set) >= n:
            return False
        # Pick first uncovered
        target = still_needed[0]
        # Try adding new element: new_b = target + bk or new_b = bk - target
        candidates = set()
        for bk in b_set:
            candidates.add(target + bk)
            candidates.add(bk - target)
        for new_b in candidates:
            new_b_set = frozenset(b_set | {new_b})
            if len(new_b_set) > len(b_set):  # actually added something
                if search(new_b_set, still_needed):
                    return True
        return False

    # Fix b_1 = 0
    initial = frozenset([0])
    if search(initial, a):
        print("YES")
    else:
        print("NO")

t = int(input())
for _ in range(t):
    solve()

